import { HealthService } from '../../services/health.service.js';
import { navigate } from '../../router.js';
import { buildSectionPage } from '../../utils/section-page.utils.js';
import './barcode-scanner/barcode-scanner.component.js';
import type { BarcodeScanner } from './barcode-scanner/barcode-scanner.component.js';
import type { ScreenComponent } from '../../types/screen-component.js';

export class HealthScannerScreen extends HTMLElement implements ScreenComponent {
    private initialized = false;
    private scanner: BarcodeScanner | null = null;
    private dateValue: string | null = null;
    private mealValue: string | null = null;
    private returnPath: string | null = null;

    setLoading(): void {}
    setError(err: unknown): void {}
    clearStatus(): void {}

    set date(value: string | null) {
        this.dateValue = value;
    }

    set meal(value: string | null) {
        this.mealValue = value;
    }

    set query(value: URLSearchParams | null) {
        this.returnPath = value?.get('return') ?? null;
    }

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;

        const page = buildSectionPage(this, 'Health', 'health', '/health');

        this.scanner = document.createElement('barcode-scanner') as BarcodeScanner;

        this.scanner.onBarcodeDetected = (barcode) => {
            const target = this.returnPath
                ? `${this.returnPath}${this.returnPath.includes('?') ? '&' : '?'}addIngredientBarcode=${encodeURIComponent(barcode)}`
                : this.dateValue && this.mealValue
                    ? `/health/food-entry/${encodeURIComponent(this.dateValue)}/${encodeURIComponent(this.mealValue)}?barcode=${encodeURIComponent(barcode)}`
                    : `/health/food-entry?barcode=${encodeURIComponent(barcode)}`;
            // Replace the scanner entry so pressing back returns to the caller / search screen,
            // not back into the scanner with the previously-scanned barcode.
            navigate(target, { history: 'replace' });
        };

        page.content.appendChild(this.scanner);
    }

    disconnectedCallback(): void {
        this.scanner?.stopCamera();
    }
}

customElements.define('health-scanner-screen', HealthScannerScreen);
